3_real_world_example.code:
function looseFunction() {
  console.log(this === window);
}
looseFunction(); // true

function strictFunction() {
  'use strict';
  console.log(this === undefined);
}
strictFunction(); // true

6_edge_case.code:
const obj = {
  name: 'Alice',
  speak() {
    setTimeout(function() {
      console.log(this.name); // undefined! (this is window)
    }, 1000);
  }
};
obj.speak();
